export interface Cruise {
  id: string;
  name: string;
  subtitle: string;
  duration: string;
  route: string;
  capacity: string;
  cabins: string;
  price: number;
  priceLabel: string;
  description: string;
  images: string[];
  facilities: string[];
  packages: CruisePackage[];
  seatPlan: Deck[];
  seatPlanImage?: string;
  menuImage?: string;
  itinerary?: ItineraryDay[];
  menu?: MenuDay[];
  safetyInfo?: string[];
  travelTips?: string[];
  thingsToCarry?: string[];
  additionalCosts?: AdditionalCost[];
  packageIncludes?: string[];
  touristSpots?: string[];
  featured: boolean;
}

export interface ItineraryDay {
  day: string;
  title: string;
  activities: string[];
}

export interface MenuDay {
  day: string;
  meals: Meal[];
}

export interface Meal {
  name: string;
  items: string;
}

export interface AdditionalCost {
  label: string;
  amount: string;
}

export interface CruisePackage {
  id: string;
  name: string;
  price: number;
  duration: string;
  image: string;
}

export interface Deck {
  name: string;
  capacity: number;
  rows: CabinRow[];
}

export interface CabinRow {
  label: string;
  cabins: Cabin[];
}

export interface Cabin {
  id: string;
  type: "Bunk" | "Single" | "Twin" | "VIP Couple" | "VIP Family";
  persons: number;
  available: boolean;
  bedType: string;
}

export interface Booking {
  id: string;
  name: string;
  email: string;
  phone: string;
  cruiseId: string;
  persons: number;
  travelDate: string;
}

export interface Testimonial {
  id: string;
  name: string;
  text: string;
  rating: number;
  avatar: string;
}

export interface TeamMember {
  id: number;
  name: string;
  role: string;
  image: string;
  bio: string;
}

