export function getCruiseById(id: string) {
  return cruises.find(c => c.id === id);
}

export function searchCruises(query: string) {
  const q = query.toLowerCase();
  return cruises.filter(c => !query || c.name.toLowerCase().includes(q) || c.route.toLowerCase().includes(q) || c.packages.some(p => p.name.toLowerCase().includes(q)));
}
